import React, { useEffect, useState, useCallback } from "react";
import { useParams, Link } from "react-router-dom";
import { api } from "../utils/api";
import { useToast } from "../utils/toast";

function formatDate(iso) {
  return new Date(iso).toLocaleDateString("en-US", {
    month: "short", day: "numeric", year: "numeric",
    hour: "numeric", minute: "2-digit",
  });
}

export default function StudentDetail() {
  const { id } = useParams();
  const [student, setStudent] = useState(null);
  const [notes, setNotes] = useState([]);
  const [newNote, setNewNote] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const toast = useToast();

  const loadNotes = useCallback(() => api.getNotes(id).then(setNotes), [id]);

  useEffect(() => {
    api.getStudent(id).then(setStudent).catch(() => setStudent(null));
    loadNotes();
  }, [id, loadNotes]);

  const addNote = async () => {
    if (!newNote.trim()) return;
    setSubmitting(true);
    try {
      await api.addNote(id, newNote.trim());
      setNewNote(""); await loadNotes(); toast("Note added ✓");
    } catch (e) { toast("Error: " + e.message); }
    finally { setSubmitting(false); }
  };

  const deleteNote = async (nid) => {
    if (!window.confirm("Delete this note?")) return;
    await api.deleteNote(nid); await loadNotes(); toast("Note deleted");
  };

  if (!student) return <div className="loading">Loading student…</div>;

  return (
    <div>
      <div className="page-header">
        <div>
          <Link to="/students" style={{ fontSize: "0.82rem", color: "var(--text-light)",
            display: "inline-flex", alignItems: "center", gap: 5, marginBottom: 8 }}>
            ← All Students
          </Link>
          <h2>{student.name}</h2>
          {student.email && (
            <p><a href={`mailto:${student.email}`} style={{ color: "var(--coral)" }}>{student.email}</a></p>
          )}
        </div>
      </div>

      {/* General notes banner */}
      {student.notes && (
        <div style={{ marginBottom: 24, padding: "14px 18px", background: "var(--violet-dim)",
          border: "1px solid rgba(167,139,250,0.2)", borderLeft: "3px solid var(--violet)",
          borderRadius: "var(--radius-lg)" }}>
          <div style={{ fontSize: "0.68rem", fontWeight: 700, textTransform: "uppercase",
            letterSpacing: "0.1em", color: "var(--violet)", marginBottom: 6 }}>General Notes</div>
          <p style={{ fontSize: "0.9rem", color: "var(--text-muted)", lineHeight: 1.6 }}>{student.notes}</p>
        </div>
      )}

      {/* Progress notes card */}
      <div className="card">
        <h3 style={{ fontFamily: "var(--font-display)", fontSize: "1.1rem", marginBottom: 20 }}>
          Progress Notes
        </h3>

        {/* Add note */}
        <div style={{ marginBottom: 28, padding: "16px", background: "var(--bg-3)",
          borderRadius: "var(--radius)", border: "1px solid var(--border)" }}>
          <textarea className="form-control"
            style={{ minHeight: 70, marginBottom: 10, background: "var(--bg-2)" }}
            placeholder='Add a progress note… e.g. "More engaged this week, asked great questions."'
            value={newNote}
            onChange={(e) => setNewNote(e.target.value)}
            onKeyDown={(e) => { if ((e.ctrlKey || e.metaKey) && e.key === "Enter") addNote(); }}
          />
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <span style={{ fontSize: "0.72rem", color: "var(--text-light)" }}>⌘ + Enter to save</span>
            <button className="btn btn-primary btn-sm" onClick={addNote}
              disabled={submitting || !newNote.trim()}>
              {submitting ? "Saving…" : "Add Note"}
            </button>
          </div>
        </div>

        {/* Notes list */}
        {notes.length === 0 ? (
          <div style={{ textAlign: "center", padding: "32px 0", color: "var(--text-muted)", fontSize: "0.88rem" }}>
            No progress notes yet.
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {notes.map((n) => (
              <div key={n._id} className="note-item">
                <div style={{ flex: 1 }}>
                  <p>{n.text}</p>
                  <time>{formatDate(n.createdAt)}</time>
                </div>
                <button className="btn btn-ghost btn-sm"
                  onClick={() => deleteNote(n._id)}
                  style={{ color: "var(--danger)", flexShrink: 0 }}>✕</button>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
